/**
 * @fileoverview DynamicSearch component definition for JIT pipeline.
 *
 * @module module/DynamicSearch.def
 */

import razyui from '../index.js';import { PART } from './DynamicSearch/constants.js';
/**
 * The definition object for the DynamicSearch component.
 * Contains configuration for tokens, states, templates, variants, and custom elements.
 *
 * @type {Object}
 */
export const DynamicSearchDef = {
    /**
     * The name of the component.
     * @type {string}
     */
    name: 'DynamicSearch',
    
    /**
     * The custom element tag name for the component.
     * @type {string}
     */
    tag: 'rui-dynamic-search',

    /**
     * Design tokens specific to the DynamicSearch component.
     * These tokens define the visual appearance of the component.
     */
    tokens: {
        prefix: 'ds',
        tokens: {
            'radius':          { ref: 'radius.sm',           description: 'Input border radius' },
            'font-size':       { ref: 'font.size-sm',        description: 'Font size' },
            'line-height':     { value: '1.25',              description: 'Line height' },
            'font-stack':      { ref: 'font.family',         description: 'Font family' },
            'accent':          { ref: 'color.accent',        description: 'Accent color' },
            'accent-subtle':   { ref: 'color.accent-subtle', description: 'Focus ring color' },
            'bg':              { ref: 'color.bg',            description: 'Background' },
            'bg-hover':        { ref: 'color.bg-hover',      description: 'Hover background' },
            'bg-inset':        { ref: 'color.bg-inset',      description: 'Disabled background' },
            'border':          { ref: 'color.border',        description: 'Border color' },
            'border-strong':   { ref: 'color.border-strong', description: 'Hover border' },
            'control-px':      { value: '0.75rem',           description: 'Control horizontal padding' },
            'control-py':      { value: '0.5rem',            description: 'Control vertical padding' },
            'gap':             { value: '0.5rem',            description: 'Internal gap' },
            'bg-raised':       { ref: 'color.bg-raised',     description: 'Raised background' },
            'shadow-lg':       { ref: 'shadow.lg',           description: 'Dropdown shadow' },
            'space-md':        { ref: 'spacing.4',           description: 'Medium spacing' },
            'space-sm':        { ref: 'spacing.2',           description: 'Small spacing' },
            'text':            { ref: 'color.text',          description: 'Text color' },
            'text-muted':      { ref: 'color.text-muted',    description: 'Muted text' },
            'z-index':         { ref: 'z-index.dropdown',    description: 'Dropdown z-index' },
        },
    },

    /**
     * State machine configuration for the DynamicSearch component.
     * Defines the possible states and transitions.
     */
    states: {
        initial: 'closed',
        states: {
            closed:   { on: { OPEN: 'open', DISABLE: 'disabled' } },
            open:     { on: { CLOSE: 'closed', SELECT: 'closed' } },
            loading:  { on: { LOADED: 'open', CLOSE: 'closed' } },
            disabled: { on: { ENABLE: 'closed' } },
        },
        effects: {
            /**
             * Effect triggered when entering the 'open' state.
             * Adds the 'is-open' class to the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            open(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-open');
            },
            /**
             * Effect triggered when exiting the 'open' state.
             * Removes the 'is-open' class from the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'open:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-open');
            },
            /**
             * Effect triggered when entering the 'disabled' state.
             * Adds the 'is-disabled' class to the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            disabled(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-disabled');
            },
            /**
             * Effect triggered when exiting the 'disabled' state.
             * Removes the 'is-disabled' class from the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'disabled:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-disabled');
            },
        },
    },

    /**
     * Template slot definitions for the DynamicSearch component.
     * Defines the HTML structure and classes for different parts of the component.
     */
    template: {
        slots: {
            root:     { element: 'div', classes: ['dynamic-search'] },
            input:    { element: 'input', classes: ['dynamic-search-input'] },
            dropdown: { element: 'div', classes: ['dynamic-search-dropdown'] },
            item:     { element: 'div', classes: ['dynamic-search-item'] },
            empty:    { element: 'div', classes: ['dynamic-search-empty'] },
            loading:  { element: 'div', classes: ['dynamic-search-loader'] },
        },
    },

    /**
     * Variants configuration for the DynamicSearch component.
     * Defines different visual or behavioral variations.
     */
    variants: {
        inline: { description: 'Inline dropdown (no absolute positioning)' },
    },

    jitParts: {
        [PART.CONTAINER]: PART.CONTAINER,
        [PART.ICON]: PART.ICON,
        [PART.SEARCH_INPUT]: PART.SEARCH_INPUT,
        [PART.LABEL]: PART.LABEL,
        [PART.SPINNER]: PART.SPINNER,
        [PART.RESET]: PART.RESET,
        [PART.FLOATING]: PART.FLOATING,
        [PART.RESULTS]: PART.RESULTS,
        [PART.ITEM]: PART.ITEM,
        [PART.EMPTY]: PART.EMPTY,
        [PART.DETAIL]: PART.DETAIL,
        [PART.EXPAND]: PART.EXPAND,
        [PART.OVERLAY]: PART.OVERLAY,
        [PART.DARKROOM]: PART.DARKROOM,
        [PART.DARKROOM_HEADER]: PART.DARKROOM_HEADER,
        [PART.DARKROOM_CLOSE]: PART.DARKROOM_CLOSE,
        [PART.DARKROOM_SEARCH]: PART.DARKROOM_SEARCH,
        [PART.DARKROOM_BODY]: PART.DARKROOM_BODY,
    },

    styles: {},

    /**
     * Observed attributes for the custom element.
     * @type {string[]}
     */
    observedAttrs: ['value', 'disabled', 'readonly', 'placeholder', 'debounce'],
    
    /**
     * Mapping of observed attributes to component properties.
     * @type {Object<string, string>}
     */
    attrMap: {
        value: 'value',
        disabled: 'disabled',
        readonly: 'readonly',
        placeholder: 'placeholder',
        debounce: 'debounce',
    },
};

export default DynamicSearchDef;
