/**
 * @fileoverview DynamicSearch events — centralised event binding via AbortController.
 * @module module/DynamicSearch/events
 */

import razyui from '../../index.js';

/**
 * Bind all static event listeners on DynamicSearch DOM elements.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {object} domRefs — { searchInput, resetBtn, container, resultList }
 * @param {object} handlers — callback map:
 *   onInput, onKeydown, onFocus, onBlur, onResetClick, onContainerClick, onResultMousedown
 * @returns {AbortController}
 */
export function bindEvents(domRefs, handlers) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    razyui(domRefs.searchInput).on('input',    handlers.onInput,       opts);
    razyui(domRefs.searchInput).on('keydown',  handlers.onKeydown,     opts);
    razyui(domRefs.searchInput).on('focus',    handlers.onFocus,       opts);
    razyui(domRefs.searchInput).on('blur',     handlers.onBlur,        opts);
    razyui(domRefs.resetBtn).on('click',       handlers.onResetClick,  opts);
    razyui(domRefs.container).on('click',      handlers.onContainerClick, opts);

    // Using mousedown (not click) so the handler fires BEFORE the input's
    // blur event — which would otherwise clear results and prevent selection.
    // preventDefault() stops the mousedown from stealing focus / triggering blur.
    razyui(domRefs.resultList).on('mousedown', handlers.onResultMousedown, opts);

    return ac;
}

/**
 * Attach a document-level outside-click listener.
 * Returns an AbortController — call `.abort()` to unbind.
 *
 * @param {HTMLElement} container — .ds-container
 * @param {HTMLElement} floating  — .ds-floating dropdown
 * @param {Function}    onClose   — callback invoked on outside click
 * @returns {AbortController}
 */
export function attachOutsideClick(container, floating, onClose) {
    const ac = new AbortController();
    razyui(document).on('mousedown', (e) => {
        if (container.contains(e.target) || floating.contains(e.target)) return;
        onClose();
    }, { signal: ac.signal });
    return ac;
}

/**
 * Bind mousedown on darkroom overlay to close when clicking outside the panel.
 *
 * @param {HTMLElement} overlay — darkroom overlay element
 * @param {Function}    onClose — callback invoked on outside click
 */
export function bindDarkroomClose(overlay, onClose) {
    razyui(overlay).on('mousedown', (e) => {
        if (e.target === overlay) onClose();
    });
}
