/**
 * @fileoverview DynamicSearch component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, ARIA attrs, SVG icons, defaults
 *   helpers.js   — escapeHTML, highlightMatch, extractValue, extractLabel
 *   state.js     — reactive state creation
 *   view.js      — DOM setup / teardown, effects, rendering, floating
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/DynamicSearch
 */

import { default as razyui } from '../../index.js';
import { DynamicSearchDef as DEF } from '../DynamicSearch.def.js';

import { DEFAULTS, CLS }                                    from './constants.js';
import { escapeHTML, extractValue, extractLabel }            from './helpers.js';
import { createReactiveState }                               from './state.js';
import { buildDOM, wireEffects, showFloating, hideFloating,
         renderResults, highlightActiveItem,
         openDarkroom, closeDarkroom, renderDarkroomResults }  from './view.js';
import { bindEvents, bindDarkroomClose }                       from './events.js';
import { attachOutsideClick }                                from '../shared/outsideClick.js';
import { emitEvent }                                         from '../shared/emitEvent.js';

/**
 * DynamicSearch — v2 modular rewrite
 *
 * Remote-search input that queries a server endpoint as the user types,
 * displays matching results in a floating dropdown, and locks the
 * display to the selected item's label.
 *
 * Features:
 *   - Debounced keystrokes → fetch JSON results
 *   - Smart floating dropdown (flip above, clamp horizontal)
 *   - Keyboard navigation (↑ ↓ Enter Esc)
 *   - Highlight matching text in results
 *   - Value / label extractors (key string or function)
 *   - Spinner while loading
 *   - Reset button to clear selection
 *   - Disabled / readonly states
 *   - Initial value → auto-resolve label
 *   - Reactive state via razyui.state()
 *   - getControl() setter API, destroy() cleanup
 *
 * Config:
 *   url         — endpoint (keyword appended as query string)
 *   minLength   — min chars before searching (default 2)
 *   debounce    — debounce ms (default 350)
 *   value       — key name or (item) => string extractor
 *   label       — key name or (item) => string extractor
 *   placeholder — input placeholder text
 *   method      — HTTP method (default 'GET')
 *   localFilter — true to filter results client-side by label (for static JSON)
 *   resolveUrl  — URL/function to resolve initial value to label
 *
 * Callbacks:
 *   onSelect(item, value)   — fires when user picks a result
 *   onReset()               — fires when selection is cleared
 *   onFetch(keyword)        — transform / return fetch params
 *   onRenderItem(item, keyword) — custom result item HTML (dropdown)
 *   onRenderDarkroomItem(item, keyword) — custom darkroom result item HTML (falls back to onRenderItem)
 *   onDrawLabel(item)       — custom selected-item label HTML
 *   onDrawDetail(item)      — custom detail HTML shown below input on select
 */
const DynamicSearch = class {
    #input = null;           // original <input> element (hidden)
    #container = null;       // .ds-container
    #searchInput = null;     // .ds-search-input
    #labelEl = null;         // .ds-label
    #resetBtn = null;        // .ds-reset
    #spinner = null;         // .ds-spinner
    #floating = null;        // .ds-floating (result dropdown)
    #resultList = null;      // .ds-results (inside floating)
    #detailEl = null;        // .ds-detail (extra info below)

    #config = {};
    #stateRef = null;
    #setState = null;
    #timer = 0;
    #destroyed = false;
    #fetchAC = null;     // AbortController for fetch
    #outsideAC = null;           // AbortController for outside-click
    #eventAC = null;            // AbortController for static event listeners
    #activeIndex = -1;           // keyboard nav index
    #results = [];               // current result items
    #overlay = null;             // darkroom: fullscreen overlay
    #darkroomBody = null;        // darkroom: results area
    #darkroomInput = null;       // darkroom: search input
    #darkroomActiveIndex = -1;   // darkroom: keyboard nav index
    #darkroomResults = [];       // darkroom: current result items
    #darkroomTimer = 0;          // darkroom: debounce timer
    #localCache = null;          // cached full dataset for localFilter mode

    constructor(selector, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // Resolve JIT spacing tokens
        this.#config.dropdownGap = razyui.JIT.TOKEN.spacePx(this.#config.dropdownGap);

        // Resolve the original <input>
        const el = razyui(selector)[0];

        if (!el || el.tagName !== 'INPUT') { console.warn('DynamicSearch: <input> element not found \u2192', selector); return; }
        this.#input = el;
        if (config.name) el.name = config.name;

        // ── Build DOM ──
        const domRefs = buildDOM(razyui, this.#config, el);
        this.#container = domRefs.container;
        this.#searchInput = domRefs.searchInput;
        this.#labelEl = domRefs.labelEl;
        this.#resetBtn = domRefs.resetBtn;
        this.#spinner = domRefs.spinner;
        this.#floating = domRefs.floating;
        this.#resultList = domRefs.resultList;
        this.#detailEl = domRefs.detailEl;

        // ── Reactive state ──
        const stateSet = createReactiveState(razyui.state, el);
        const [stateRef, setState] = stateSet;
        this.#stateRef = stateRef;
        this.#setState = setState;

        const self = this;

        // ── Wire effects ──
        wireEffects(stateSet, {
            container: this.#container,
            searchInput: this.#searchInput,
            labelEl: this.#labelEl,
            resetBtn: this.#resetBtn,
            spinner: this.#spinner,
            input: this.#input,
        }, {
            isInline: !!config.renderContext,
            getResults: () => self.#results,
            showFloatingFn: () => showFloating(self.#container, self.#floating, self.#config.dropdownGap),
            hideFloatingFn: () => hideFloating(self.#floating, self.#container),
        });

        // ── Event listeners ──
        this.#eventAC = bindEvents({
            searchInput: this.#searchInput,
            resetBtn: this.#resetBtn,
            container: this.#container,
            resultList: this.#resultList,
        }, {
            onInput: (e) => {
                const keyword = e.target.value;
                // Reset button only appears when an item is selected (locked),
                // never for mere typed text — DynamicSearch is search-and-pick only.
                razyui(self.#resetBtn).toggleClass(CLS.HIDDEN, !stateRef.locked);
                self.#debouncedSearch(keyword);
            },
            onKeydown: (e) => {
                self.#handleKeydown(e);
            },
            onFocus: () => {
                if (stateRef.disabled || stateRef.readonly) return;
                if (self.#results.length > 0 && self.#searchInput.value.length >= self.#config.minLength) {
                    setState({ open: true });
                    self.#attachOutsideClick();
                }
            },
            // If the user blurs without selecting an item, clear the typed text
            // so that DynamicSearch always acts as search-and-pick (no custom text).
            onBlur: () => {
                // Small delay so that a click on a result item can fire first
                setTimeout(() => {
                    if (!stateRef.locked) {
                        self.#searchInput.value = '';
                        razyui(self.#resetBtn).addClass(CLS.HIDDEN);
                        self.#results = [];
                        self.#activeIndex = -1;
                        setState({ open: false });
                        self.#detachOutsideClick();
                    }
                }, DEFAULTS.blurDelay);
            },
            onResetClick: (e) => {
                e.preventDefault();
                e.stopPropagation();
                if (stateRef.readonly || stateRef.disabled) return;
                self.#resetSelection();
            },
            // Click anywhere on container → focus search input
            onContainerClick: () => {
                if (!self.#searchInput.disabled && !razyui(self.#searchInput).hasClass(CLS.HIDDEN)) {
                    self.#searchInput.focus();
                }
            },
            // Delegated mousedown on result items.
            // Using mousedown (not click) so the handler fires BEFORE the input's
            // blur event — which would otherwise clear results and prevent selection.
            // preventDefault() stops the mousedown from stealing focus / triggering blur.
            onResultMousedown: (e) => {
                const item = e.target.closest('.' + CLS.ITEM);
                if (!item) return;
                e.preventDefault();   // keep focus on search input (prevent blur)
                e.stopPropagation();
                const idx = parseInt(item.dataset.index, 10);
                if (idx >= 0 && idx < self.#results.length) {
                    self.#selectItem(self.#results[idx]);
                }
            },
        });

        // ── Darkroom expand button ──
        if (domRefs.expandBtn) {
            razyui(domRefs.expandBtn).on('click', (e) => {
                e.stopPropagation();
                self.#openDarkroom();
            });
        }

        // ── Resolve initial value ──
        if (el.value) {
            this.#resolveInitial(el.value);
        }
    }

    // ────────────────────────────────────────────
    // Search logic
    // ────────────────────────────────────────────

    #debouncedSearch(keyword) {
        clearTimeout(this.#timer);
        if (keyword.length < this.#config.minLength) {
            this.#results = [];
            this.#setState({ open: false });
            return;
        }

        this.#timer = setTimeout(() => {
            this.#fetchResults(keyword);
        }, this.#config.debounce);
    }

    async #fetchResults(keyword) {
        const cfg = this.#config;
        if (!cfg.url) return;

        // ── localFilter: reuse cached dataset (avoid re-fetching the full list) ──
        if (cfg.localFilter && this.#localCache) {
            const kw = keyword.toLowerCase();
            const data = this.#localCache.filter(item => {
                const lbl = extractLabel(item, cfg).toLowerCase();
                return lbl.includes(kw) || Object.values(item).some(
                    v => typeof v === 'string' && v.toLowerCase().includes(kw)
                );
            });
            this.#results = data;
            this.#activeIndex = -1;
            renderResults(this.#resultList, data, keyword, cfg, (item) => extractLabel(item, cfg));
            this.#setState({ open: data.length > 0 });
            if (data.length > 0) this.#attachOutsideClick();
            return;
        }

        // Cancel previous in-flight request
        this.#fetchAC?.abort();
        this.#fetchAC = new AbortController();

        this.#setState({ loading: true });

        try {
            let data;

            if (typeof cfg.url === 'function') {
                // Callback mode — the function returns a result (or promise)
                data = await cfg.url(keyword);
            } else {
                let url = cfg.url;
                let fetchOpts = {
                    method: cfg.method,
                    signal: this.#fetchAC.signal,
                    headers: { 'Content-Type': 'application/json' },
                };

                // Build request
                if (typeof cfg.onFetch === 'function') {
                    const custom = await cfg.onFetch(keyword);
                    if (typeof custom === 'string') {
                        url = custom;
                    } else if (razyui.isPO(custom)) {
                        if (custom.url) url = custom.url;
                        if (custom.body) fetchOpts.body = JSON.stringify(custom.body);
                        if (custom.method) fetchOpts.method = custom.method;
                    }
                } else if (!cfg.localFilter) {
                    // Default: append keyword as query param
                    const sep = url.includes('?') ? '&' : '?';
                    url = url + sep + 'q=' + encodeURIComponent(keyword);
                }

                const response = await fetch(url, fetchOpts);
                if (!response.ok) throw new Error(response.statusText);
                data = await response.json();
            }

            // Normalize: if data is wrapped in a property, allow config to unwrap
            if (!Array.isArray(data)) {
                // Try common wrapper keys
                data = data.data || data.results || data.items || data.response || [];
            }
            if (!Array.isArray(data)) data = [];

            // Cache full dataset for localFilter (before filtering)
            if (cfg.localFilter && typeof cfg.url !== 'function' && typeof cfg.onFetch !== 'function') {
                this.#localCache = data;
            }

            // Client-side filtering (for static JSON files)
            if (cfg.localFilter) {
                const kw = keyword.toLowerCase();
                data = data.filter(item => {
                    const lbl = extractLabel(item, cfg).toLowerCase();
                    // Also check all string values in the item
                    return lbl.includes(kw) || Object.values(item).some(
                        v => typeof v === 'string' && v.toLowerCase().includes(kw)
                    );
                });
            }

            this.#results = data;
            this.#activeIndex = -1;
            renderResults(this.#resultList, data, keyword, cfg, (item) => extractLabel(item, cfg));
            this.#setState({ open: data.length > 0 });

            if (data.length > 0) {
                this.#attachOutsideClick();
            }
        } catch (err) {
            if (err.name !== 'AbortError') {
                this.#results = [];
                this.#setState({ open: false });
            }
        } finally {
            this.#setState({ loading: false });
        }
    }

    // ────────────────────────────────────────────
    // Selection
    // ────────────────────────────────────────────

    #selectItem(item) {
        const val = extractValue(item, this.#config);
        let labelHTML;

        if (typeof this.#config.onDrawLabel === 'function') {
            labelHTML = this.#config.onDrawLabel(item);
        } else {
            labelHTML = escapeHTML(extractLabel(item, this.#config));
        }

        razyui(this.#labelEl).html(labelHTML);
        this.#searchInput.value = '';
        this.#results = [];
        this.#activeIndex = -1;

        this.#setState({
            value: val,
            selectedItem: item,
            locked: true,
            open: false,
        });

        // Show detail area if callback provided
        if (typeof this.#config.onDrawDetail === 'function') {
            const html = this.#config.onDrawDetail(item);
            const $detail = razyui(this.#detailEl);
            if (html) {
                $detail.html(html);
                $detail.removeClass(CLS.HIDDEN);
            } else {
                $detail.addClass(CLS.HIDDEN);
            }
        }

        this.#detachOutsideClick();

        emitEvent(this.#container, 'select', { item, value: val });
        if (typeof this.#config.onSelect === 'function') {
            this.#config.onSelect.call(this, item, val);
        }
    }

    #resetSelection() {
        this.#searchInput.value = '';
        this.#input.value = '';
        this.#results = [];
        this.#activeIndex = -1;

        // Hide detail area
        razyui(this.#detailEl).html('').addClass(CLS.HIDDEN);

        this.#setState({
            value: '',
            selectedItem: null,
            locked: false,
            open: false,
        });

        this.#detachOutsideClick();
        this.#searchInput.focus();

        emitEvent(this.#container, 'reset');
        if (typeof this.#config.onReset === 'function') {
            this.#config.onReset.call(this);
        }
    }

    // ────────────────────────────────────────────
    // Resolve initial value
    // ────────────────────────────────────────────

    async #resolveInitial(value) {
        const cfg = this.#config;
        if (!cfg.resolveUrl && !cfg.url) return;

        this.#setState({ loading: true });

        try {
            let data;

            // resolveUrl can be a callback function
            if (typeof cfg.resolveUrl === 'function') {
                data = await cfg.resolveUrl(value);
            } else if (typeof cfg.url === 'function') {
                // url is callback — call it with value as keyword for resolve
                data = await cfg.url(value);
            } else {
                let url;
                if (typeof cfg.resolveUrl === 'string') {
                    const sep = cfg.resolveUrl.includes('?') ? '&' : '?';
                    url = cfg.resolveUrl + sep + 'id=' + encodeURIComponent(value);
                } else {
                    // fallback: use main url
                    if (cfg.localFilter) {
                        url = cfg.url;
                    } else {
                        const sep = cfg.url.includes('?') ? '&' : '?';
                        url = cfg.url + sep + 'id=' + encodeURIComponent(value);
                    }
                }

                const response = await fetch(url);
                if (!response.ok) throw new Error(response.statusText);
                data = await response.json();
            }

            // localFilter: fetch full array and find the matching item
            if (cfg.localFilter && Array.isArray(data)) {
                const v = String(value);
                data = data.find(item => String(extractValue(item, cfg)) === v) || null;
            } else if (Array.isArray(data)) {
                data = data[0];
            } else if (!data.id && !data.value && !data.name) {
                data = data.data || data.result || data.response || data;
            }

            if (data) {
                const val = extractValue(data, cfg);
                let labelHTML;
                if (typeof cfg.onDrawLabel === 'function') {
                    labelHTML = cfg.onDrawLabel(data);
                } else {
                    labelHTML = escapeHTML(extractLabel(data, cfg));
                }

                razyui(this.#labelEl).html(labelHTML);
                this.#setState({
                    value: val,
                    selectedItem: data,
                    locked: true,
                });

                // Show detail area if callback provided
                if (typeof cfg.onDrawDetail === 'function') {
                    const detailHTML = cfg.onDrawDetail(data);
                    if (detailHTML) {
                        razyui(this.#detailEl).html(detailHTML).removeClass(CLS.HIDDEN);
                    }
                }
            }
        } catch {
            // Silently fail — user can still search
        } finally {
            this.#setState({ loading: false });
        }
    }

    // ────────────────────────────────────────────
    // Keyboard navigation
    // ────────────────────────────────────────────

    #handleKeydown(e) {
        if (!this.#stateRef.open) {
            if (e.key === 'Escape') {
                this.#searchInput.blur();
            }
            return;
        }

        const items = razyui(this.#resultList).find('.' + CLS.ITEM);
        const count = items.length;

        switch (e.key) {
            case 'ArrowDown':
                e.preventDefault();
                this.#activeIndex = Math.min(this.#activeIndex + 1, count - 1);
                highlightActiveItem(items, this.#activeIndex);
                break;

            case 'ArrowUp':
                e.preventDefault();
                this.#activeIndex = Math.max(this.#activeIndex - 1, 0);
                highlightActiveItem(items, this.#activeIndex);
                break;

            case 'Enter':
                e.preventDefault();
                if (this.#activeIndex >= 0 && this.#activeIndex < this.#results.length) {
                    this.#selectItem(this.#results[this.#activeIndex]);
                }
                break;

            case 'Escape':
                e.preventDefault();
                this.#setState({ open: false });
                this.#detachOutsideClick();
                break;
        }
    }

    // ────────────────────────────────────────────
    // Outside click
    // ────────────────────────────────────────────

    #attachOutsideClick() {
        if (this.#outsideAC) return;
        this.#outsideAC = attachOutsideClick(this.#container, this.#floating, () => {
            this.#setState({ open: false });
            this.#detachOutsideClick();
        });
    }

    #detachOutsideClick() {
        this.#outsideAC?.abort();
        this.#outsideAC = null;
    }

    // ────────────────────────────────────────────
    // Darkroom
    // ────────────────────────────────────────────

    /** Open fullscreen darkroom overlay. */
    #openDarkroom() {
        if (this.#stateRef.disabled || this.#stateRef.readonly) return;
        if (this.#overlay) return; // prevent duplicate overlays

        // Close normal dropdown if open
        if (this.#stateRef.open) {
            this.#setState({ open: false });
            this.#detachOutsideClick();
        }

        const self = this;
        this.#darkroomResults = [];
        this.#darkroomActiveIndex = -1;

        const drRefs = openDarkroom(razyui, this.#config, this.#input, {
            onClose: () => self.#closeDarkroom(),
            onSearch: (keyword) => {
                self.#debouncedDarkroomSearch(keyword);
            },
            onItemClick: (idx) => {
                if (idx >= 0 && idx < self.#darkroomResults.length) {
                    self.#selectItem(self.#darkroomResults[idx]);
                    self.#closeDarkroom();
                }
            },
            onKeydown: (e, bodyEl) => {
                self.#handleDarkroomKeydown(e, bodyEl);
            },
        });

        this.#overlay = drRefs.overlay;
        this.#darkroomBody = drRefs.darkroomBody;
        this.#darkroomInput = drRefs.darkroomInput;
        bindDarkroomClose(this.#overlay, () => self.#closeDarkroom());
    }

    /** Close darkroom overlay. */
    #closeDarkroom() {
        clearTimeout(this.#darkroomTimer);
        closeDarkroom(this.#overlay);
        this.#overlay = null;
        this.#darkroomBody = null;
        this.#darkroomInput = null;
        this.#darkroomResults = [];
        this.#darkroomActiveIndex = -1;
    }

    /** Debounced search within the darkroom. */
    #debouncedDarkroomSearch(keyword) {
        clearTimeout(this.#darkroomTimer);
        if (keyword.length < this.#config.minLength) {
            this.#darkroomResults = [];
            this.#darkroomActiveIndex = -1;
            if (this.#darkroomBody) {
                razyui(this.#darkroomBody).html('');
            }
            return;
        }

        this.#darkroomTimer = setTimeout(() => {
            this.#fetchDarkroomResults(keyword);
        }, this.#config.debounce);
    }

    /** Fetch and render results inside the darkroom. */
    async #fetchDarkroomResults(keyword) {
        const cfg = this.#config;
        if (!cfg.url) return;

        // ── localFilter: reuse cached dataset (avoid re-fetching the full list) ──
        if (cfg.localFilter && this.#localCache) {
            const kw = keyword.toLowerCase();
            const data = this.#localCache.filter(item => {
                const lbl = extractLabel(item, cfg).toLowerCase();
                return lbl.includes(kw) || Object.values(item).some(
                    v => typeof v === 'string' && v.toLowerCase().includes(kw)
                );
            });
            this.#darkroomResults = data;
            this.#darkroomActiveIndex = -1;
            if (this.#darkroomBody) {
                renderDarkroomResults(
                    this.#darkroomBody, data, keyword, cfg,
                    (item) => extractLabel(item, cfg)
                );
            }
            return;
        }

        // Cancel previous in-flight request
        this.#fetchAC?.abort();
        this.#fetchAC = new AbortController();

        try {
            let data;

            if (typeof cfg.url === 'function') {
                data = await cfg.url(keyword);
            } else {
                let url = cfg.url;
                let fetchOpts = {
                    method: cfg.method,
                    signal: this.#fetchAC.signal,
                    headers: { 'Content-Type': 'application/json' },
                };

                if (typeof cfg.onFetch === 'function') {
                    const custom = await cfg.onFetch(keyword);
                    if (typeof custom === 'string') {
                        url = custom;
                    } else if (razyui.isPO(custom)) {
                        if (custom.url) url = custom.url;
                        if (custom.body) fetchOpts.body = JSON.stringify(custom.body);
                        if (custom.method) fetchOpts.method = custom.method;
                    }
                } else if (!cfg.localFilter) {
                    const sep = url.includes('?') ? '&' : '?';
                    url = url + sep + 'q=' + encodeURIComponent(keyword);
                }

                const response = await fetch(url, fetchOpts);
                if (!response.ok) throw new Error(response.statusText);
                data = await response.json();
            }

            if (!Array.isArray(data)) {
                data = data.data || data.results || data.items || data.response || [];
            }
            if (!Array.isArray(data)) data = [];

            // Cache full dataset for localFilter (before filtering)
            if (cfg.localFilter && typeof cfg.url !== 'function' && typeof cfg.onFetch !== 'function') {
                this.#localCache = data;
            }

            if (cfg.localFilter) {
                const kw = keyword.toLowerCase();
                data = data.filter(item => {
                    const lbl = extractLabel(item, cfg).toLowerCase();
                    return lbl.includes(kw) || Object.values(item).some(
                        v => typeof v === 'string' && v.toLowerCase().includes(kw)
                    );
                });
            }

            this.#darkroomResults = data;
            this.#darkroomActiveIndex = -1;

            if (this.#darkroomBody) {
                renderDarkroomResults(
                    this.#darkroomBody, data, keyword, cfg,
                    (item) => extractLabel(item, cfg)
                );
            }
        } catch (err) {
            if (err.name !== 'AbortError') {
                this.#darkroomResults = [];
                if (this.#darkroomBody) {
                    razyui(this.#darkroomBody).html('');
                }
            }
        }
    }

    /** Keyboard navigation inside the darkroom. */
    #handleDarkroomKeydown(e, bodyEl) {
        const items = razyui(bodyEl).find('.' + CLS.ITEM);
        const count = items.length;

        switch (e.key) {
            case 'ArrowDown':
                e.preventDefault();
                this.#darkroomActiveIndex = Math.min(this.#darkroomActiveIndex + 1, count - 1);
                highlightActiveItem(items, this.#darkroomActiveIndex);
                break;

            case 'ArrowUp':
                e.preventDefault();
                this.#darkroomActiveIndex = Math.max(this.#darkroomActiveIndex - 1, 0);
                highlightActiveItem(items, this.#darkroomActiveIndex);
                break;

            case 'Enter':
                e.preventDefault();
                if (this.#darkroomActiveIndex >= 0 && this.#darkroomActiveIndex < this.#darkroomResults.length) {
                    this.#selectItem(this.#darkroomResults[this.#darkroomActiveIndex]);
                    this.#closeDarkroom();
                }
                break;

            case 'Escape':
                e.preventDefault();
                this.#closeDarkroom();
                break;
        }
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    /** Get the current value. */
    getValue() { return this.#stateRef.value; }

    /** Set value programmatically (does NOT resolve label — use forceValue for that). */
    setValue(value) {
        this.#setState({ value });
        this.#input.value = value ?? '';
        emitEvent(this.#container, 'change', { value });
    }

    /** Set value + label directly without fetching. */
    forceValue(value, label) {
        razyui(this.#labelEl).html(typeof label === 'string' ? label : '');
        this.#input.value = value ?? '';
        this.#setState({ value, locked: !!value, selectedItem: null });
    }

    /** Get the full data object of the selected item. */
    getSelectedItem() { return this.#stateRef.selectedItem; }

    /** Clear selection and reset to empty. */
    reset() { this.#resetSelection(); }

    /** Set disabled state. */
    setDisabled(disabled) {
        this.#setState({ disabled: !!disabled });
        this.#input.disabled = !!disabled;
        this.#container.setAttribute('aria-disabled', String(!!disabled));
    }

    setInvalid(invalid) {
        this.#container.classList.toggle(CLS.INVALID, !!invalid);
        this.#container[invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    focus() { this.#searchInput?.focus(); }
    blur()  { this.#searchInput?.blur(); }

    clear() { this.reset(); }

    open() {
        if (this.#stateRef.disabled || this.#stateRef.readonly) return;
        if (!this.#stateRef.open) {
            this.#setState({ open: true });
            this.#attachOutsideClick();
        }
    }

    close() {
        if (this.#stateRef.open) {
            this.#setState({ open: false });
            this.#detachOutsideClick();
        }
    }

    toggle() { this.#stateRef.open ? this.close() : this.open(); }
    get isOpen() { return !!this.#stateRef.open; }

    /** Set readonly state. */
    setReadonly(readonly) {
        this.#setState({ readonly: !!readonly });
        this.#container.setAttribute('aria-readonly', String(!!readonly));
    }

    /**
     * Return a control object with property setters.
     *   ctrl.value          — get/set value
     *   ctrl.disabled       — get/set disabled
     *   ctrl.readonly       — get/set readonly
     *   ctrl.selectedItem   — get selected data object
     */
    getControl() {
        const self = this;
        return {
            get value() { return self.getValue(); },
            set value(v) { self.setValue(v); },
            get disabled() { return self.#stateRef.disabled; },
            set disabled(v) { self.setDisabled(v); },
            get readonly() { return self.#stateRef.readonly; },
            set readonly(v) { self.setReadonly(v); },
            get required() { return self.#input.required; },
            set required(v) { self.#input.required = !!v; self.#container.setAttribute('aria-required', String(!!v)); },
            get selectedItem() { return self.getSelectedItem(); },
            reset:             () => self.reset(),
            clear:             () => self.clear(),
            forceValue:        (v, l) => self.forceValue(v, l),
            setInvalid:        (v) => self.setInvalid(v),
            checkValidity:     () => self.#input.checkValidity(),
            reportValidity:    () => self.#input.reportValidity(),
            setCustomValidity: (m) => { self.#input.setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label() { return self.#container.getAttribute('aria-label'); },
            set label(v) { v ? self.#container.setAttribute('aria-label', v) : self.#container.removeAttribute('aria-label'); },
            get labelledby() { return self.#container.getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#container.setAttribute('aria-labelledby', v) : self.#container.removeAttribute('aria-labelledby'); },
            get describedby() { return self.#container.getAttribute('aria-describedby'); },
            set describedby(v) { v ? self.#container.setAttribute('aria-describedby', v) : self.#container.removeAttribute('aria-describedby'); },
            focus:  () => self.focus(),
            blur:   () => self.blur(),
            open:   () => self.open(),
            close:  () => self.close(),
            toggle: () => self.toggle(),
            get isOpen() { return self.isOpen; },
            get loading() { return self.#stateRef.loading; },
            destroy: () => self.destroy(),
            get name() { return self.#input.name; },
            set name(v) { self.#input.name = v ?? ''; },
            get element() { return self.#container; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Tear down — restore original input. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        clearTimeout(this.#timer);
        this.#closeDarkroom();
        this.#fetchAC?.abort();
        this.#eventAC?.abort();
        this.#detachOutsideClick();
        this.#localCache = null;
        if (this.#floating.parentNode) this.#floating.remove();
        if (this.#detailEl.parentNode) this.#detailEl.remove();

        // Remove container
        const containerEl = this.#container;
        if (containerEl && containerEl.parentNode) {
            containerEl.remove();
        }

        razyui(this.#input).css('display', '');
    }
};

export default DynamicSearch;
