/**
 * @fileoverview DynamicSearch view — DOM setup / teardown, effects, rendering.
 * @module module/DynamicSearch/view
 */

import razyui from '../../index.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';
import { CLS, SVG, SPELL, TEXT, ARIA, PART } from './constants.js';
import { highlightMatch } from './helpers.js';
import { positionFloating } from '../shared/positionFloating.js';
import { setContent } from '../shared/setContent.js';

// ═══════════════════════════════════════
//  DOM Construction
// ═══════════════════════════════════════

/**
 * Build the DynamicSearch DOM structure around the original input.
 *
 * @param {object} razyui — razyui core reference
 * @param {object} config — component config
 * @param {HTMLInputElement} input — original input element (will be hidden)
 * @returns {{ container, searchInput, labelEl, resetBtn, spinner, floating, resultList, detailEl }}
 */
export function buildDOM(razyui, config, input) {
    // Build container structure via spell()
    const dom = razyui.spell(SPELL.CONTAINER, true);
    const container = dom[0];
    razyui(container).addClass('dynamic-search');
    PART.CONTAINER.apply(container);

    // When rendered inside another component (e.g. GridTable cell), apply inline mode
    if (config.renderContext) {
        razyui(container).addClass(CLS.INLINE);
    }

    // Collect all child elements in a single traversal (pos=0 → single Elements each)
    const { icon, searchInput, label, spinner, resetBtn } = dom.collect({
        icon: '.' + CLS.ICON,
        searchInput: '.' + CLS.SEARCH_INPUT,
        label: '.' + CLS.LABEL,
        spinner: '.' + CLS.SPINNER,
        resetBtn: '.' + CLS.RESET,
    }, 0);

    // Search icon SVG
    icon.html(SVG.SEARCH_ICON);
    PART.ICON.apply(icon);

    // Search input attributes
    searchInput.attr({ type: 'text', placeholder: config.placeholder, autocomplete: 'off' });
    PART.SEARCH_INPUT.apply(searchInput);

    PART.LABEL.apply(label);

    // Spinner SVG
    spinner.html(SVG.SPINNER_ICON)
           .css('display', 'none');
    PART.SPINNER.apply(spinner);

    // Reset button attributes
    resetBtn.attr({ type: 'button', 'aria-label': ARIA.CLEAR_LABEL }).html(TEXT.RESET_LABEL);
    PART.RESET.apply(resetBtn);

    // Floating dropdown
    const floatingDom = razyui.spell(SPELL.FLOATING, true);
    const floating = floatingDom[0];
    razyui(floating).addClass('dynamic-search');
    PART.FLOATING.apply(floating);
    const { results: resultList } = floatingDom.collect({ results: '.' + CLS.RESULTS }, 0);
    PART.RESULTS.apply(resultList);
    razyui(floating).css('display', 'none');

    // Detail area (below container)
    const detail = razyui.spell(SPELL.DETAIL, true)[0];
    PART.DETAIL.apply(detail);

    // Insert into DOM
    razyui(input).css('display', 'none');
    input.parentNode.insertBefore(container, input.nextSibling);
    container.parentNode.insertBefore(detail, container.nextSibling);

    // Display mode setup: darkroom (expand button inside container)
    let expandBtn = null;
    if (config.display === 'darkroom') {
        expandBtn = PART.EXPAND.create({ type: 'button', title: TEXT.EXPAND_TITLE, innerHTML: SVG.EXPAND });
        razyui(container).append(expandBtn);
    }

    return {
        container,
        searchInput: searchInput[0],
        labelEl: label[0],
        resetBtn: resetBtn[0],
        spinner: spinner[0],
        floating,
        resultList: resultList[0],
        detailEl: detail,
        expandBtn,
    };
}

// ═══════════════════════════════════════
//  Reactive State Effects
// ═══════════════════════════════════════

/**
 * Wire reactive state effects to DOM elements.
 *
 * @param {Array} stateSet — state set from createReactiveState (has .effect())
 * @param {object} domRefs — { container, searchInput, labelEl, resetBtn, spinner, input }
 * @param {object} opts
 * @param {boolean} opts.isInline — suppress spinner in inline mode
 * @param {Function} opts.getResults — () => current results array
 * @param {Function} opts.showFloatingFn — callback to position + show dropdown
 * @param {Function} opts.hideFloatingFn — callback to hide dropdown
 */
export function wireEffects(stateSet, domRefs, { isInline, getResults, showFloatingFn, hideFloatingFn }) {
    const { container, searchInput, labelEl, resetBtn, spinner, input } = domRefs;
    const $container = razyui(container);
    const $searchInput = razyui(searchInput);
    const $labelEl = razyui(labelEl);
    const $resetBtn = razyui(resetBtn);
    const $spinner = razyui(spinner);

    // Effect 1: sync disabled / readonly
    stateSet.effect(function () {
        $container.toggleClass(CLS.DISABLED, !!this.disabled);
        $container.toggleClass(CLS.READONLY, !!this.readonly);
        searchInput.disabled = !!this.disabled || !!this.readonly;
    });

    // Effect 2: sync locked state (selected label vs search input)
    stateSet.effect(function () {
        if (this.locked) {
            $searchInput.addClass(CLS.HIDDEN);
            $labelEl.removeClass(CLS.HIDDEN);
            // Hide reset button when readonly (user cannot clear)
            $resetBtn.toggleClass(CLS.HIDDEN, !!this.readonly);
            $container.addClass(CLS.LOCKED);
        } else {
            $searchInput.removeClass(CLS.HIDDEN);
            $labelEl.addClass(CLS.HIDDEN);
            $container.removeClass(CLS.LOCKED);
            // Show reset only if there's text in the search input
            if (!searchInput.value) {
                $resetBtn.addClass(CLS.HIDDEN);
            }
        }
    });

    // Effect 3: loading spinner + cloak (hidden in inline mode — too noisy in cells)
    stateSet.effect(function () {
        const isLoading = !isInline && this.loading;
        $spinner.css('display', isLoading ? '' : 'none');
        $container.toggleClass('is-loading', isLoading);
        $container[0].setAttribute('aria-busy', String(!!isLoading));
    });

    // Effect 4: sync open (floating dropdown)
    stateSet.effect(function () {
        if (this.open && getResults().length > 0) {
            showFloatingFn();
        } else {
            hideFloatingFn();
        }
    });

    // Effect 5: sync value back to original input
    stateSet.effect(function () {
        input.value = this.value || '';
    });
}

// ═══════════════════════════════════════
//  Floating Dropdown Positioning
// ═══════════════════════════════════════

/**
 * Position and show the floating dropdown relative to the container.
 *
 * @param {HTMLElement} container — .ds-container
 * @param {HTMLElement} floating  — .ds-floating dropdown
 * @param {number} dropdownGap   — gap in px between container and dropdown
 */
export function showFloating(container, floating, dropdownGap) {
    const $container = razyui(container);

    if (!floating.isConnected) razyui(document.body).append(floating);

    const { flipped } = positionFloating(floating, container, {
        strategy: 'fixed',
        gap:      dropdownGap,
        flip:     true,
        width:    'match',
    });

    if (flipped) {
        $container.addClass(CLS.FLIPPED);
    } else {
        $container.removeClass(CLS.FLIPPED);
    }

    $container.addClass(CLS.OPEN);
    zIndexRegistry.acquire(floating);
}

/**
 * Hide the floating dropdown.
 *
 * @param {HTMLElement} floating  — .ds-floating dropdown
 * @param {HTMLElement} container — .ds-container
 */
export function hideFloating(floating, container) {
    zIndexRegistry.release(floating);
    razyui(floating).css('display', 'none');
    razyui(container).removeClass(CLS.OPEN).removeClass(CLS.FLIPPED);
}

// ═══════════════════════════════════════
//  Rendering
// ═══════════════════════════════════════

/**
 * Render search results into the dropdown list.
 *
 * @param {HTMLElement} resultList    — .ds-results container
 * @param {Array}       data         — result items
 * @param {string}      keyword      — current search keyword
 * @param {object}      config       — component config (for onRenderItem)
 * @param {Function}    extractLabelFn — (item) => label string
 */
export function renderResults(resultList, data, keyword, config, extractLabelFn) {
    const $resultList = razyui(resultList);
    $resultList.html('');

    if (data.length === 0) {
        const empty = PART.EMPTY.create({ textContent: TEXT.NO_RESULTS });
        $resultList.append(empty);
        return;
    }

    data.forEach((item, i) => {
        const el = PART.ITEM.create({ 'data-index': i });

        if (typeof config.onRenderItem === 'function') {
            setContent(el, config.onRenderItem(item, keyword));
        } else {
            const labelText = extractLabelFn(item);
            el.html(highlightMatch(labelText, keyword));
        }

        $resultList.append(el);
    });
}

/**
 * Highlight the active keyboard-navigated item and scroll it into view.
 *
 * @param {NodeList} items       — .ds-item elements
 * @param {number}   activeIndex — currently active index
 */
export function highlightActiveItem(items, activeIndex) {
    items.each((el, i) => {
        razyui(el).toggleClass(CLS.ACTIVE, i === activeIndex);
    });
    // Scroll into view
    if (items[activeIndex]) {
        items[activeIndex].scrollIntoView({ block: 'nearest' });
    }
}

// ═══════════════════════════════════════
//  Darkroom
// ═══════════════════════════════════════

/**
 * Open fullscreen darkroom overlay for DynamicSearch.
 *
 * @param {object}   razyui    — razyui core reference
 * @param {object}   config    — component config
 * @param {HTMLInputElement} inputEl — original input element (for data-theme)
 * @param {object}   callbacks — { onClose, onSearch(keyword), onItemClick(index), onKeydown(e, bodyEl) }
 * @returns {{ overlay: HTMLElement, darkroomBody: HTMLElement, darkroomInput: HTMLInputElement }}
 */
export function openDarkroom(razyui, config, inputEl, callbacks) {
    const dom = razyui.spell(SPELL.DARKROOM, true);
    const overlay = dom[0];
    PART.OVERLAY.apply(overlay);
    PART.DARKROOM.apply(dom.find('.' + CLS.DARKROOM)[0]);

    const { title, closeBtn, searchInput, body } = dom.collect({
        title: '.' + CLS.DARKROOM_HEADER + ' > span',
        closeBtn: '.' + CLS.DARKROOM_CLOSE,
        searchInput: '.' + CLS.DARKROOM_SEARCH,
        body: '.' + CLS.DARKROOM_BODY,
    }, 0);

    title.text(config.placeholder || 'Search');
    PART.DARKROOM_HEADER.apply(dom.find('.' + CLS.DARKROOM_HEADER)[0]);
    closeBtn.attr('type', 'button').html(TEXT.CLOSE_HTML);
    PART.DARKROOM_CLOSE.apply(closeBtn);
    searchInput.attr({ type: 'text', placeholder: config.placeholder || 'Search…', autocomplete: 'off' });
    PART.DARKROOM_SEARCH.apply(searchInput);

    const bodyEl = body[0];
    PART.DARKROOM_BODY.apply(body);
    const searchEl = searchInput[0];
    razyui(document.body).append(overlay);

    // Inherit data-theme from nearest themed ancestor so dark mode works
    const themed = inputEl.closest('[data-theme]');
    if (themed) {
        overlay.setAttribute('data-theme', themed.getAttribute('data-theme'));
    }

    // Acquire z-index from central registry
    zIndexRegistry.acquire(overlay);

    // Focus the search input
    requestAnimationFrame(() => searchEl.focus());

    // ── Event wiring ──
    closeBtn.on('click', () => callbacks.onClose());
    searchInput.on('input', () => callbacks.onSearch(searchEl.value));
    searchInput.on('keydown', (e) => callbacks.onKeydown(e, bodyEl));
    body.on('mousedown', (e) => {
        const item = e.target.closest('.' + CLS.ITEM);
        if (!item) return;
        e.preventDefault();
        const idx = parseInt(item.dataset.index, 10);
        if (idx >= 0) callbacks.onItemClick(idx);
    });

    // Prevent body scroll
    razyui(document.body).css('overflow', 'hidden');

    return { overlay, darkroomBody: bodyEl, darkroomInput: searchEl };
}

/**
 * Render search results into the darkroom body.
 * Uses `config.onRenderDarkroomItem` if provided, otherwise falls back to
 * `config.onRenderItem`, matching Combobox's onRenderDarkroom / onRenderOption pattern.
 *
 * @param {HTMLElement} bodyEl     — .ds-darkroom-body container
 * @param {Array}       data       — result items
 * @param {string}      keyword    — current search keyword
 * @param {object}      config     — component config
 * @param {Function}    extractLabelFn — (item) => label string
 */
export function renderDarkroomResults(bodyEl, data, keyword, config, extractLabelFn) {
    const $body = razyui(bodyEl);
    $body.html('');

    if (data.length === 0) {
        const empty = PART.EMPTY.create({ textContent: TEXT.NO_RESULTS });
        $body.append(empty);
        return;
    }

    const renderer = config.onRenderDarkroomItem || config.onRenderItem;

    data.forEach((item, i) => {
        const el = PART.ITEM.create({ 'data-index': i });

        if (typeof renderer === 'function') {
            setContent(el, renderer(item, keyword));
        } else {
            const labelText = extractLabelFn(item);
            el.html(highlightMatch(labelText, keyword));
        }

        $body.append(el);
    });
}

/**
 * Close darkroom overlay and restore body scroll.
 *
 * @param {HTMLElement|null} overlay — darkroom overlay element
 */
export function closeDarkroom(overlay) {
    if (overlay) {
        zIndexRegistry.release(overlay);
        overlay.remove();
    }
    razyui(document.body).css('overflow', '');
}
